import{_ as o,o as r,c as t,ai as s}from"./chunks/framework.B3x_xFnx.js";const c=JSON.parse('{"title":"Guide for reporting bugs","description":"","frontmatter":{},"headers":[],"relativePath":"guides/BugReport.md","filePath":"guides/BugReport.md"}'),i={name:"guides/BugReport.md"};function n(a,e,l,g,u,d){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="guide-for-reporting-bugs" tabindex="-1">Guide for reporting bugs <a class="header-anchor" href="#guide-for-reporting-bugs" aria-label="Permalink to “Guide for reporting bugs”">​</a></h1><p>Before <strong>reporting a bug</strong>, please follow these guidelines to ensure that your report is as useful as possible:</p><ol><li>Search the group or forum to see if the <strong>bug has already been reported</strong>.</li><li>Try <strong>rebooting your device</strong> to see if this resolves the issue.</li><li>Perform a <strong>clean flash</strong> of the ROM by formatting data/factory resetting using the recommended recovery.</li><li>Check for the bug before installing any additional modifications, like <strong>Magisk modules</strong>.</li><li>Use the <strong>default kernel</strong> that came with the ROM.</li><li>Use the <strong>recovery</strong> recommended by the maintainer.</li></ol><p>Only report bugs after you have followed all of the above mentioned guidelines</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Reports from users who have not followed these guidelines, such as <strong>decrypted users</strong>, users who have <strong>changed the kernel</strong>, or users who have not performed a <strong>clean flash</strong> when instructed to, may be ignored.</p></div><p>When reporting a bug, be sure to include the following information:</p><ul><li>Your <strong>device variant</strong></li><li>The version of <strong>PixelOS</strong> you are using</li><li>Any relevant <strong>logs</strong> (by reading <a href="./HowToLog.html">this guide</a>).</li></ul>',7)])])}cons